Implementasi Observer Pattern menggunakan Python `abc` untuk strict typing dan decoupling yang ketat. Kode ini dirancang untuk skalabilitas dan handling error yang aman agar kegagalan satu observer tidak mengganggu notifikasi ke observer lain.

```python
from abc import ABC, abstractmethod
from typing import List
import logging

# Konfigurasi Logging untuk Audit Trail
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject(ABC):
    _observers: List[Observer]

    def __init__(self):
        self._observers = []

    def attach(self, observer: Observer) -> None:
        if observer not in self._observers:
            self._observers.append(observer)
            logger.info(f"Observer attached: {observer.__class__.__name__}")

    def detach(self, observer: Observer) -> None:
        try:
            self._observers.remove(observer)
            logger.info(f"Observer detached: {observer.__class__.__name__}")
        except ValueError:
            logger.warning(f"Observer not found: {observer.__class__.__name__}")

    def notify(self) -> None:
        for observer in self._observers:
            try:
                observer.update(self)
            except Exception as e:
                # Critical: Catch exceptions to prevent one faulty observer from stopping others
                logger.error(f"Error notifying {observer.__class__.__name__}: {e}")

class SecurityEventSystem(Subject):
    def __init__(self):
        super().__init__()
        self._event_type = ""
        self._severity = 0

    def trigger_event(self, event_type: str, severity: int) -> None:
        self._event_type = event_type
        self._severity = severity
        logger.info(f"Event Triggered: {event_type} (Severity: {severity})")
        self.notify()

    @property
    def event_type(self) -> str:
        return self._event_type

    @property
    def severity(self) -> int:
        return self._severity

class EmailAlertObserver(Observer):
    def update(self, subject: SecurityEventSystem) -> None:
        if subject.severity >= 5:
            # Simulasi pengiriman email
            logger.info(f"[EMAIL] Sending alert for {subject.event_type}")

class LogAnalyzerObserver(Observer):
    def update(self, subject: SecurityEventSystem) -> None:
        # Simulasi logging ke SIEM
        logger.info(f"[SIEM] Logging event: {subject.event_type} - Severity {subject.severity}")

# Usage
if __name__ == "__main__":
    system = SecurityEventSystem()
    email_alert = EmailAlertObserver()
    log_analyzer = LogAnalyzerObserver()

    system.attach(email_alert)
    system.attach(log_analyzer)

    # Trigger Security Event
    system.trigger_event("SQL_INJECTION_ATTEMPT", 8)
```

### Technical Notes:
1.  **Exception Handling**: Blok `try-except` di method `notify` wajib ada. Dalam produksi, observer yang crash tidak boleh menghentikan loop notifikasi (Fail-safe).
2.  **Type Hinting**: Menggunakan `typing` untuk memastikan integritas data yang passed antar objek.
3.  **Logging**: Setiap attach/detect/notify dicatat untuk audit trail keamanan.
4.  **Decoupling**: `Subject` tidak tahu detail konkret `Observer`, memudahkan maintenance dan penambahan fitur baru tanpa modifikasi core logic.

Gunakan pola ini untuk sistem monitoring, alerting keamanan, atau update state real-time. Pastikan tidak ada logic berat di dalam method `update` observer untuk menghindari blocking pada subject utama.
